# utils/model_utils.pyimport pickleimport numpy as npimport pandas as pdimport streamlit as stfrom config import MODEL_PATH@st.cache_resource(show_spinner=False)def load_model():    """Charge le modèle depuis MODEL_PATH. Si absent, retourne un modèle factice."""    if MODEL_PATH is None or MODEL_PATH == "":        st.warning("⚠️ Aucun modèle configuré. Utilisation d'un modèle factice (aléatoire).")        return None   # sera géré dans predict()    try:        with open(MODEL_PATH, "rb") as f:            return pickle.load(f)    except FileNotFoundError:        st.warning(f"Fichier modèle introuvable : {MODEL_PATH}. Utilisation d'un modèle factice.")        return None    except Exception as e:        st.error(f"Erreur lors du chargement du modèle : {e}")        return Nonedef build_input_row(    ap_dep, ap_arr, compagnie, pays_dep, pays_arr,    heure_h, mois, jour_sem,    distance, taxi_time, temps_vol,    hauteur_dep, hauteur_arr,    lat_dep, lon_dep, lat_arr, lon_arr,) -> pd.DataFrame:    """Construit 1 ligne compatible avec le pipeline ML de crm.py."""    eps = 1e-6    # Encodage cyclique    mois_sin  = np.sin(2*np.pi*mois/12);     mois_cos  = np.cos(2*np.pi*mois/12)    jour_sin  = np.sin(2*np.pi*jour_sem/7);  jour_cos  = np.cos(2*np.pi*jour_sem/7)    heure_sin = np.sin(2*np.pi*heure_h/24);  heure_cos = np.cos(2*np.pi*heure_h/24)    # Haversine    R = 6371.0    la1,lo1,la2,lo2 = map(np.radians,[lat_dep,lon_dep,lat_arr,lon_arr])    a = np.sin((la2-la1)/2)**2 + np.cos(la1)*np.cos(la2)*np.sin((lo2-lo1)/2)**2    dist_hav = 2*R*np.arcsin(np.sqrt(max(a,0)))    # Segment    if distance<=500:       seg="Court"    elif distance<=1500:    seg="Moyen"    elif distance<=3000:    seg="Long"    else:                   seg="Ultra_long"    # Créneau    creneau_map = {(0,5):"Nuit",(6,8):"Tôt_matin",(9,11):"Matin",                   (12,14):"Midi",(15,17):"Apres_midi",(18,20):"Soiree",(21,24):"Nuit_tardive"}    creneau = "Matin"    for (lo,hi),lbl in creneau_map.items():        if lo<=heure_h<=hi: creneau=lbl; break    is_soiree = int(18<=heure_h<=23)    is_ete    = int(mois in [6,7,8])    row = {        "TAXI_TIME"       : taxi_time,        "TEMPS_VOL"       : temps_vol,        "DISTANCE"        : distance,        "DIST_HAVERSINE"  : dist_hav,        "LOG_DIST"        : np.log1p(distance),        "HAUTEUR_DEP"     : hauteur_dep,        "HAUTEUR_ARR"     : hauteur_arr,        "DIFF_HAUTEUR"    : hauteur_arr - hauteur_dep,        "MOIS_SIN"        : mois_sin,        "MOIS_COS"        : mois_cos,        "JOUR_SIN"        : jour_sin,        "JOUR_COS"        : jour_cos,        "HEURE_SIN"       : heure_sin,        "HEURE_COS"       : heure_cos,        "VOL_AP_DEP"      : 500,        "TAXI_x_SOIREE"   : taxi_time * is_soiree,        "DIST_x_ETE"      : distance * is_ete,        "COMPAGNIE"       : compagnie,        "AP_DEP"          : ap_dep,        "AP_ARR"          : ap_arr,        "PAYS_DEP"        : pays_dep,        "PAYS_ARR"        : pays_arr,        "CRENEAU"         : creneau,        "SEGMENT_DIST"    : seg,    }    return pd.DataFrame([row])def predict(model, input_df):    """Retourne (proba, classe, top_feats). Gère le cas où model est None (modèle factice)."""    if model is None:        # Modèle factice simple (aléatoire mais cohérent avec les données)        h  = input_df["HEURE_SIN"].iloc[0]   # proxy heure        tt = input_df["TAXI_TIME"].iloc[0]        base = 0.25        if input_df["DIST_x_ETE"].iloc[0] > 0: base += 0.08        if tt > 30:  base += 0.12        if input_df["TAXI_x_SOIREE"].iloc[0] > 0: base += 0.15        proba  = min(base + np.random.uniform(-0.05,0.05), 0.99)        classe = int(proba >= 0.5)        feats  = [("Taxi time",tt,tt>30),("Heure",h,True),("Distance",input_df["DISTANCE"].iloc[0],True)]        return proba, classe, feats    # Modèle réel chargé    proba  = model.predict_proba(input_df)[0,1]    classe = int(proba >= 0.5)    try:        clf       = model.named_steps["classifier"]        pre       = model.named_steps["preprocessor"]        feat_names = pre.get_feature_names_out()        imps      = (clf.feature_importances_                     if hasattr(clf,"feature_importances_")                     else np.abs(clf.coef_[0]))        top_idx   = np.argsort(imps)[::-1][:5]        top_feats = [(feat_names[i], imps[i], True) for i in top_idx]    except Exception:        top_feats = []    return proba, classe, top_feats